public String plusOut(String str, String word)
{
    String nw = "";
    int lw = word.length();
    int ls = str.length();
    int lim = ls - lw;
    int i = 0;
    int n;
    while (i <= lim)
    {
        int lwi = i + lw;
        n = lwi;
        String o = str.substring(i, lwi);
        if (word.equals(o))
        {
            nw = nw + word;
            i = i + lw;
        }
        else
        {
            nw = nw + "+";
        }
        i = i + 1;
    }
    return nw;
}

