    for (int i = 0; i < nums.length; i++) 
    {
        sum += nums[i];
        if (nums[i] > max) 
        {
            max = nums[i];
        }
        if (nums[i] < min) 
        {
            min = nums[i];
        }
    }
    return (sum - (max + min)) / (nums.length - 2);
}

public int sum67(int[] nums)
{
    int sum = 0;
    for (int i = 0, i < nums.length; i++) {
        if (nums.get(i) = 6) {
            while (nums.get(i) != 7) {
                i++;
            }
        }
        else {
            sum += nums.get(i);
        }
    }
}

