public boolean evenlySpaced(int a, int b, int c)
{
    if (a != b && a != c && b != c)
    {
         return (Math.abs(b - a) == Math.abs(c - b) 
         || Math.abs(b - a) == Math.abs(c - a)
         || Math.abs(a - b) == Math.abs(c - b)
         || Math.abs(c - a) == Math.abs(b - c) 
         || a == b && b == c);
    }
    return false;
}

public String repeatEnd(String str, int n)
{
    String newString;
    int length = str.length() - n;
    newString = str.substring(length, str.length());
    for (int x = 1; x < n; x++)
    {
        newString = newString + newString;
    }
    return newString;
}

public int[] zeroMax(int[] nums)
{
    for(int i =0; i < nums.length; i++)
    {
        if(nums[i] == 0)
        {
            nums[i] = largestOdd(nums);
        }

    }

     return nums;

}

public int largestOdd(int[] xyz)
{
    int max = xyz[0];
    for( int i = 0; i < xyz.length - 1; i++)
    {
        if(xyz[i] == 0)
        {
            max = xyz[i+1];
            for(int x = 1; x < xyz.length-i; x++)
            {
                if(xyz[i + x] > max && xyz[i+x]%2 == 1)
              {
                max = xyz[i+x];
              }
            }
        }
    }
    return max;
}

public String without2(String str) 
{
    String part = str.substring(2);
    int end = str.length();
    String part2 = str.substring(end - 2, end);
    if (str.length() == 2)
    {
        return part;
    }
    else if (part != part2)
    {
    	return str;
    }
    else
    {
        return part;
    }
}

public int countCode(String str)
{
    int times = 0;
    int l = str.length()-3;
    int i = 0;
    while(i <  l) {
		if(str.charAt(i) == 'c' && str.charAt(i+1) == 'o' 	          && str.charAt(i+3) == 'e') {
			times++;
			i += 4;
       	}
		else {
			i+=1;
		}
	return times;
}

public int countClumps(int[] nums)
{
    int clumps = 0;
	boolean isClump = false;
  for(int i = 0; i < nums.length - 1; i++)
  {
  	if(isClump)
  	{
	  	if(nums[i] != nums[i+1])
	  		isClump = false;
	  }
  	else if(nums[i] == nums[i+1])
  	{
  		isClump = true;
  		clumps++;
  	}
  }
  return clumps;
}

