public int centeredAverage(int[] nums)
{
  int max = nums[0];
	int min = nums[0];
	int sum = nums[0];
	for(int i = 1; i < nums.length; i++)
	{
		sum  += nums[i];
		if(nums[i] > max)
			max = nums[i];
		else if(nums[i] < min)
			min = nums[i];
	}
	return (sum-max-min) / (nums.length - 2);
}

public boolean evenlySpaced(int a, int b, int c)
{
    int big = c;
    int small = b;
    int medium = a;
    if(a > b && a > c)
    {
        if(b > c)
        {
            big = a;
            medium = b;
            small = c;
        }
        else
        {
            big = a;
            medium = c;
            small = b;
        }
    }
    else
    {
        if(a > c)
        {
            big = b;
            medium = a;
            small = c;
        }
        else
        {
            big = b;
            medium = c;
            small = a;
        }
    }
    if((big - medium) == (medium - small))
    {
        return true;
    }
    else
    {
        return false;
    }
}

public String atFirst(String str)
{
    int length = str.length();
    String atFirst;

    if (length = 0)
    {
        atFirst = "@@";
    }
    else if (length = 1);
    {
        atFirst = str.substring(0, 1) + "@";
    }
    else
    {
        atFirst = str.substring(0, 2);
    }
    return atFirst;
}

public int[] seriesUp(int n)
{
    int[] nums = new int[n * (n + 1) / 2];
    int count = 0;
    for (int i = 0; i < nums.length; i++)
    {
        i = count;
		for (int j = 1; j <= (j * (j + 1) / 2); j++)
        {
            if (i < nums.length)
            {
                nums[i] = j;
                i++;
                count++;
            }
        }
    }
    return nums;
}

